import SwiftUI

struct InputRowView: View {
    @ObservedObject var viewModel: TaskViewModel
    @FocusState.Binding var isInputFocused: Bool

    var body: some View {
        HStack(spacing: 12) {
            TextField("Add a new task...", text: $viewModel.newTaskTitle)
                .font(.body)
                .padding(.horizontal, 16)
                .padding(.vertical, 14)
                .background(
