                    .font(.system(size: 18, weight: .semibold))
                    .foregroundStyle(.white)
                    .frame(width: 48, height: 48)
                    .background(
                        RoundedRectangle(cornerRadius: 14)
                            .fill(
                                viewModel.newTaskTitle.trimmingCharacters(in: .whitespaces).isEmpty
                                ? Color(.systemGray3)
                                : Color.indigo
                            )
                            .shadow(color: Color.indigo.opacity(0.35), radius: 6, x: 0, y: 3)
                    )
            }
            .buttonStyle(.plain)
            .disabled(viewModel.newTaskTitle.trimmingCharacters(in: .whitespaces).isEmpty)
            .animation(.easeInOut(duration: 0.2), value: viewModel.newTaskTitle)
            .accessibilityLabel("Add task")
        }
    }
}

